import React, { useEffect, useState } from "react";
import styled, { keyframes } from "styled-components";

/**
 * StainedGlassCurtain — gothic cathedral rose-window splash.
 *
 * 37 hand-built polygon shards arranged as a cathedral rosette around the
 * viewport center: a central topaz hex, six inner ruby/sapphire petals, six
 * emerald/amethyst outer kites, twelve trapezoid shards forming the outer
 * ring, and twelve quadrilateral shards reaching to the viewport edges.
 *
 * Each shard's fill-opacity animates 0 → 1 with a staggered delay, sweeping
 * outward from the center as if backlit by a slow sunrise. Once every shard
 * is lit, a warm white-amber radial flash washes through the window and
 * fades, like sun cresting the horizon behind the glass.
 *
 * All shards share a thick black lead stroke (#0A0A0A) and the background
 * gap colour is also lead — so any uncovered viewport corners read as
 * masonry frame rather than empty space.
 *
 * Total runtime ≈ 1.85s before fade trigger (plus 400ms fade out).
 */

// ===== timing =====
const SHARD_FADE_MS = 320;
const SHARD_STAGGER_MS = 30; // each shard starts 30ms after the previous one
const FLASH_AT = 1500; // ms — radial sunrise flash begins
const FLASH_DUR = 360;
const TITLE_AT = 900; // ms — title reveals while shards are still lighting
const HOLD_MS = 1850; // total runtime before fade trigger
const FADE_MS = 400;
const TOTAL_MS = HOLD_MS + FADE_MS;

// ===== jewel palette =====
const RUBY = "#B5152C";
const SAPPHIRE = "#1944A8";
const EMERALD = "#0E7A4D";
const AMETHYST = "#6A2A8C";
const TOPAZ = "#D9A024";
const LEAD = "#0A0A0A";

// ===== keyframes =====
// Each shard fades its fill-opacity from 0 → 1 with a small mid-rise dip
// so the glass reads as "settling" after first catching the light rather
// than snapping flat.
const lightOn = keyframes`
  0%   { fill-opacity: 0; }
  55%  { fill-opacity: 1; }
  72%  { fill-opacity: 0.88; }
  100% { fill-opacity: 1; }
`;

// Warm radial wash — rises bright, then fades to nothing.
const sunrise = keyframes`
  0%   { opacity: 0; }
  35%  { opacity: 0.58; }
  100% { opacity: 0; }
`;

const titleReveal = keyframes`
  0%   { opacity: 0; transform: translateY(8px); letter-spacing: 0.06em; }
  100% { opacity: 1; transform: translateY(0);   letter-spacing: 0.18em; }
`;

// ===== styled =====
const Wrap = styled.div`
  position: fixed;
  inset: 0;
  z-index: 9999;
  pointer-events: none;
  background: ${LEAD};
  overflow: hidden;
  transition: opacity ${FADE_MS}ms ease;
  opacity: ${({ $fade }) => ($fade ? 0 : 1)};
`;

const Window = styled.svg`
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;

  .shard {
    fill-opacity: 0;
    stroke: ${LEAD};
    stroke-linejoin: round;
    stroke-linecap: round;
    animation: ${lightOn} ${SHARD_FADE_MS}ms cubic-bezier(0.22, 1, 0.36, 1)
      both;
  }
`;

const Flash = styled.div`
  position: absolute;
  inset: 0;
  background: radial-gradient(
    ellipse 75% 75% at 50% 50%,
    rgba(255, 232, 175, 0.95) 0%,
    rgba(255, 220, 150, 0.55) 40%,
    rgba(255, 200, 110, 0) 80%
  );
  mix-blend-mode: screen;
  opacity: 0;
  animation: ${sunrise} ${FLASH_DUR}ms ease-out ${FLASH_AT}ms both;
  z-index: 2;
`;

const Title = styled.div`
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 16px;
  z-index: 3;
  text-align: center;
  font-family: -apple-system, "Inter", "Helvetica Neue", Arial, sans-serif;
  opacity: 0;
  animation: ${titleReveal} 700ms cubic-bezier(0.16, 1, 0.3, 1) ${TITLE_AT}ms
    both;

  .name {
    font-size: clamp(28px, 5.4vw, 58px);
    font-weight: 900;
    letter-spacing: 0.18em;
    color: #fff6e2;
    text-shadow:
      0 0 14px rgba(255, 220, 140, 0.55),
      0 0 2px rgba(10, 10, 10, 0.9),
      0 1px 0 rgba(10, 10, 10, 0.8);

    span {
      color: ${RUBY};
      text-shadow:
        0 0 14px rgba(181, 21, 44, 0.7),
        0 0 2px rgba(10, 10, 10, 0.9);
      margin-left: 0.02em;
    }
  }

  .tagline {
    font-family: "SF Mono", "JetBrains Mono", Menlo, Consolas, monospace;
    font-size: clamp(10px, 1.1vw, 12px);
    color: rgba(255, 240, 200, 0.82);
    letter-spacing: 0.34em;
    text-transform: uppercase;
    text-shadow: 0 0 8px rgba(255, 220, 140, 0.4);
  }
`;

// ===== shard data =====
//
// 37 polygons designed against a 1000×600 viewBox, centred on (500, 300).
// Layout (in light-up order):
//   1  central hexagon            (r ≈ 50)
//   6  inner petal triangles      (apex r = 130, at 30°, 90°, 150°, 210°, 270°, 330°)
//   6  outer hex-vertex kites     (apex r = 130, at 0°, 60°, 120°, 180°, 240°, 300°)
//  12  ring-2 trapezoid shards    (r 130 → r 270)
//  12  outer-edge quads           (r 270 → viewport boundary)
//
// Stroke width steps up slightly with radius so the outer leads feel chunkier.
// Colours rotate through the five jewel tones; adjacent shards always carry
// different hues so the lead between reads as a real glass line.
const SHARDS = [
  // 0 — central eye (topaz)
  { c: TOPAZ, pts: "550,300 525,343 475,343 450,300 475,257 525,257", sw: 4 },

  // 1-6 — inner petals (sapphire / ruby alternating)
  { c: SAPPHIRE, pts: "550,300 613,365 525,343", sw: 4 },
  { c: RUBY, pts: "525,343 500,430 475,343", sw: 4 },
  { c: SAPPHIRE, pts: "475,343 387,365 450,300", sw: 4 },
  { c: RUBY, pts: "450,300 387,235 475,257", sw: 4 },
  { c: SAPPHIRE, pts: "475,257 500,170 525,257", sw: 4 },
  { c: RUBY, pts: "525,257 613,235 550,300", sw: 4 },

  // 7-12 — outer hex-vertex kites (emerald / amethyst alternating)
  { c: EMERALD, pts: "550,300 613,365 630,300 613,235", sw: 4 },
  { c: AMETHYST, pts: "525,343 500,430 565,413 613,365", sw: 4 },
  { c: EMERALD, pts: "475,343 387,365 435,413 500,430", sw: 4 },
  { c: AMETHYST, pts: "450,300 387,235 370,300 387,365", sw: 4 },
  { c: EMERALD, pts: "475,257 500,170 435,187 387,235", sw: 4 },
  { c: AMETHYST, pts: "525,257 613,235 565,187 500,170", sw: 4 },

  // 13-24 — ring-2 trapezoid shards (rotate 5 colours, every 30°)
  { c: RUBY, pts: "630,300 770,300 734,435 613,365", sw: 5 },
  { c: SAPPHIRE, pts: "613,365 734,435 635,534 565,413", sw: 5 },
  { c: EMERALD, pts: "565,413 635,534 500,570 500,430", sw: 5 },
  { c: AMETHYST, pts: "500,430 500,570 365,534 435,413", sw: 5 },
  { c: TOPAZ, pts: "435,413 365,534 266,435 387,365", sw: 5 },
  { c: RUBY, pts: "387,365 266,435 230,300 370,300", sw: 5 },
  { c: SAPPHIRE, pts: "370,300 230,300 266,165 387,235", sw: 5 },
  { c: EMERALD, pts: "387,235 266,165 365,66 435,187", sw: 5 },
  { c: AMETHYST, pts: "435,187 365,66 500,30 500,170", sw: 5 },
  { c: TOPAZ, pts: "500,170 500,30 635,66 565,187", sw: 5 },
  { c: RUBY, pts: "565,187 635,66 734,165 613,235", sw: 5 },
  { c: SAPPHIRE, pts: "613,235 734,165 770,300 630,300", sw: 5 },

  // 25-36 — outer-edge quads (r 270 → viewport boundary, rotate 5 colours)
  { c: EMERALD, pts: "770,300 1000,300 1000,589 734,435", sw: 5 },
  { c: AMETHYST, pts: "734,435 1000,589 673,600 635,534", sw: 5 },
  { c: TOPAZ, pts: "635,534 673,600 500,600 500,570", sw: 5 },
  { c: RUBY, pts: "500,570 500,600 327,600 365,534", sw: 5 },
  { c: SAPPHIRE, pts: "365,534 327,600 0,589 266,435", sw: 5 },
  { c: EMERALD, pts: "266,435 0,589 0,300 230,300", sw: 5 },
  { c: AMETHYST, pts: "230,300 0,300 0,11 266,165", sw: 5 },
  { c: TOPAZ, pts: "266,165 0,11 327,0 365,66", sw: 5 },
  { c: RUBY, pts: "365,66 327,0 500,0 500,30", sw: 5 },
  { c: SAPPHIRE, pts: "500,30 500,0 673,0 635,66", sw: 5 },
  { c: EMERALD, pts: "635,66 673,0 1000,11 734,165", sw: 5 },
  { c: AMETHYST, pts: "734,165 1000,11 1000,300 770,300", sw: 5 },
];

const StainedGlassCurtain = ({ onFinish }) => {
  const [fade, setFade] = useState(false);
  const [done, setDone] = useState(false);

  useEffect(() => {
    const fadeT = setTimeout(() => setFade(true), HOLD_MS);
    const doneT = setTimeout(() => {
      setDone(true);
      if (onFinish) onFinish();
    }, TOTAL_MS);
    return () => {
      clearTimeout(fadeT);
      clearTimeout(doneT);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (done) return null;

  return (
    <Wrap $fade={fade}>
      <Window viewBox="0 0 1000 600" preserveAspectRatio="none">
        {SHARDS.map((s, i) => (
          <polygon
            key={i}
            className="shard"
            points={s.pts}
            fill={s.c}
            strokeWidth={s.sw}
            style={{ animationDelay: `${i * SHARD_STAGGER_MS}ms` }}
          />
        ))}
      </Window>

      <Flash />

      <Title>
        <div className="name">
          DIBYAJYOTI<span>.</span>
        </div>
        <div className="tagline">Senior Software Engineer · London</div>
      </Title>
    </Wrap>
  );
};

export default StainedGlassCurtain;
